const input = $input.first().json;

return [{
  json: {
    trace_id: input.MessageSid ?? null,
    workflow_name: '[Luxee] Inbox — Inbound SMS Handler',
    source_system: 'twilio',
    entity_type: 'message',
    message: {
      direction: 'inbound',
      body: input.Body ?? null,
      external_message_id: input.MessageSid ?? null,
      status: 'received',
      subject: null,
      media_url: input.MediaUrl0 ?? null,
      num_media: parseInt(input.NumMedia ?? '0', 10)
    },
    conversation: {
      channel_connection_id: null,
      external_contact_id: input.From ?? null,
      status: 'open',
      is_new: false
    },
    contact: {
      phone: input.From ?? null,
      known_contact_id: null
    },
    channel: {
      type: 'sms',
      from: input.From ?? null,
      to: input.To ?? null,
      provider: 'twilio',
      account_sid: input.AccountSid ?? null
    },
    ai: {
      intent: null,
      summary: null,
      sentiment: null,
      priority_score: null,
      suggested_reply: null,
      qualification_stage: null,
      tags: []
    },
    routing: {
      assigned_to: null,
      team: null,
      escalated: false
    },
    meta: {
      from_country: input.FromCountry ?? null,
      from_city: input.FromCity ?? null,
      from_state: input.FromState ?? null,
      num_segments: input.NumSegments ?? null,
      sms_status: input.SmsStatus ?? null
    },
    raw_payload: input
  }
}];

const data = $input.first().json;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/messages',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY
  },
  qs: {
    external_message_id: 'eq.' + data.trace_id,
    select: 'id',
    limit: '1'
  },
  json: true
});

return [{
  json: {
    ...data,
    _idempotency: {
      is_duplicate: Array.isArray(response) && response.length > 0,
      existing_message_id: Array.isArray(response) && response.length > 0 ? response[0].id : null
    }
  }
}];

const data = $input.first().json;

await this.helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_URL + '/rest/v1/events_log',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: {
    event_type: 'message.duplicate_skipped',
    actor_type: 'workflow',
    actor_id: '[Luxee] Inbox — Inbound SMS Handler',
    workflow_trace_id: data.trace_id,
    status: 'skipped',
    payload: {
      source_system: data.source_system,
      external_message_id: data.message.external_message_id,
      existing_message_id: data._idempotency.existing_message_id
    }
  },
  json: true
});

return [$input.first()];

const data = $input.first().json;
const toPhone = data.channel.to;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/channel_connections',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY
  },
  qs: {
    channel: 'eq.sms',
    external_identifier: 'eq.' + toPhone,
    is_active: 'eq.true',
    select: 'id,label,config',
    limit: '1'
  },
  json: true
});

const found = Array.isArray(response) && response.length > 0;

return [{
  json: {
    ...data,
    conversation: {
      ...data.conversation,
      channel_connection_id: found ? response[0].id : null
    },
    _channel: {
      found: found,
      label: found ? response[0].label : null,
      config: found ? response[0].config : null
    }
  }
}];

const data = $input.first().json;
const phone = data.contact.phone;

// 1. Try to find existing contact by phone
const existing = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/contacts',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY
  },
  qs: {
    phone: 'eq.' + phone,
    select: 'id,full_name,company',
    limit: '1'
  },
  json: true
});

let contactId;
let isNewContact = false;

if (Array.isArray(existing) && existing.length > 0) {
  // Known contact
  contactId = existing[0].id;
} else {
  // Create minimal contact — enrichment happens in AI workflow
  const created = await this.helpers.httpRequest({
    method: 'POST',
    url: $env.SUPABASE_URL + '/rest/v1/contacts',
    headers: {
      'apikey': $env.SUPABASE_SERVICE_KEY,
      'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: { phone: phone },
    json: true
  });
  const result = Array.isArray(created) ? created[0] : created;
  contactId = result.id;
  isNewContact = true;
}

return [{
  json: {
    ...data,
    contact: {
      ...data.contact,
      known_contact_id: contactId
    },
    _contact: {
      id: contactId,
      is_new: isNewContact
    }
  }
}];

const data = $input.first().json;
const channelConnectionId = data.conversation.channel_connection_id;
const contactId = data._contact.id;
const phone = data.contact.phone;

// 1. Look for an existing open conversation
const existing = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/conversations',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY
  },
  qs: {
    channel_connection_id: 'eq.' + channelConnectionId,
    contact_id: 'eq.' + contactId,
    status: 'not.in.(resolved,archived,spam)',
    select: 'id,status',
    order: 'created_at.desc',
    limit: '1'
  },
  json: true
});

let conversationId;
let isNew = false;

if (Array.isArray(existing) && existing.length > 0) {
  conversationId = existing[0].id;
} else {
  // Create new conversation
  const created = await this.helpers.httpRequest({
    method: 'POST',
    url: $env.SUPABASE_URL + '/rest/v1/conversations',
    headers: {
      'apikey': $env.SUPABASE_SERVICE_KEY,
      'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: {
      channel_connection_id: channelConnectionId,
      contact_id: contactId,
      external_contact_id: phone,
      status: 'open',
      is_read: false,
      last_workflow_trace_id: data.trace_id
    },
    json: true
  });
  const result = Array.isArray(created) ? created[0] : created;
  conversationId = result.id;
  isNew = true;
}

return [{
  json: {
    ...data,
    conversation: {
      ...data.conversation,
      id: conversationId,
      is_new: isNew
    },
    _conversation: {
      id: conversationId,
      is_new: isNew
    }
  }
}];

const data = $input.first().json;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_URL + '/rest/v1/messages',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=representation'
  },
  body: {
    conversation_id: data.conversation.id,
    channel_connection_id: data.conversation.channel_connection_id,
    direction: 'inbound',
    status: 'received',
    body: data.message.body,
    subject: null,
    external_message_id: data.message.external_message_id,
    source_system: 'twilio',
    raw_payload: data.raw_payload,
    workflow_trace_id: data.trace_id
  },
  json: true
});

const result = Array.isArray(response) ? response[0] : response;

return [{
  json: {
    ...data,
    _inserted_message: {
      id: result.id
    }
  }
}];

const data = $input.first().json;

await this.helpers.httpRequest({
  method: 'PATCH',
  url: $env.SUPABASE_URL + '/rest/v1/conversations?id=eq.' + data.conversation.id,
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: {
    last_message_at: new Date().toISOString(),
    is_read: false,
    last_workflow_trace_id: data.trace_id,
    contact_id: data._contact.id
  },
  json: true
});

return [$input.first()];

const data = $input.first().json;

// Fire-and-forget: do not block main pipeline on AI latency
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: $env.N8N_WEBHOOK_AI_ANALYZER,
    headers: {
      'Content-Type': 'application/json'
    },
    body: {
      conversation_id: data.conversation.id,
      message_id: data._inserted_message.id,
      trace_id: data.trace_id
    },
    json: true,
    timeout: 3000
  });
} catch (e) {
  // Intentionally swallowed — AI failure must not block inbound pipeline
}

return [$input.first()];

const data = $input.first().json;

await this.helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_URL + '/rest/v1/events_log',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: {
    event_type: 'message.received',
    actor_type: 'workflow',
    actor_id: '[Luxee] Inbox — Inbound SMS Handler',
    conversation_id: data.conversation.id,
    workflow_trace_id: data.trace_id,
    status: 'success',
    payload: {
      source_system: data.source_system,
      channel: 'sms',
      from: data.channel.from,
      message_id: data._inserted_message.id,
      is_new_conversation: data._conversation.is_new,
      is_new_contact: data._contact.is_new
    }
  },
  json: true
});

return [$input.first()];

const data = $input.first().json;

let error_type = 'unknown';
let is_fatal = false;
let should_alert = false;
let description = 'An unknown error occurred in the SMS handler pipeline';

if (data._channel && data._channel.found === false) {
  // Came from PROCESSING Channel Connection Found? false path
  error_type = 'channel_not_configured';
  is_fatal = true;
  should_alert = true;
  description = 'No active SMS channel_connection found for To number: ' + (data.channel ? data.channel.to : 'unknown');
} else if (!data._channel) {
  // Came from VALIDATION false path — infer which field failed
  const missing = [];
  if (!data.message || !data.message.external_message_id) missing.push('external_message_id');
  if (!data.message || !data.message.body) missing.push('message.body');
  if (!data.channel || !data.channel.from || !/^\+\d{7,15}$/.test(data.channel.from)) missing.push('channel.from (must be E.164)');
  error_type = 'validation_failed';
  is_fatal = false;
  should_alert = false;
  description = 'Validation failed: ' + (missing.length ? missing.join(', ') : 'unknown field');
}

return [{
  json: {
    ...data,
    _classified_error: {
      error_type: error_type,
      is_fatal: is_fatal,
      should_alert: should_alert,
      description: description,
      timestamp: new Date().toISOString(),
      trace_id: data.trace_id
    }
  }
}];

const data = $input.first().json;
const err = data._classified_error;

await this.helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_URL + '/rest/v1/events_log',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: {
    event_type: 'workflow.error',
    actor_type: 'workflow',
    actor_id: '[Luxee] Inbox — Inbound SMS Handler',
    workflow_trace_id: err.trace_id,
    status: 'failure',
    payload: {
      error_type: err.error_type,
      description: err.description,
      is_fatal: err.is_fatal,
      source_system: data.source_system,
      channel_from: data.channel ? data.channel.from : null,
      channel_to: data.channel ? data.channel.to : null
    }
  },
  json: true
});

return [$input.first()];

const data = $input.first().json;
const err = data._classified_error;

// Only alert for fatal errors that need human action
if (!err || !err.should_alert) {
  return [$input.first()];
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: $env.SLACK_WEBHOOK_OPS,
    headers: {
      'Content-Type': 'application/json'
    },
    body: {
      text: ':rotating_light: *[Luxee] Inbox — Fatal SMS Handler Error*',
      blocks: [
        {
          type: 'header',
          text: { type: 'plain_text', text: ':rotating_light: Luxee Inbox — Fatal Error' }
        },
        {
          type: 'section',
          fields: [
            { type: 'mrkdwn', text: '*Error type:*\n' + err.error_type },
            { type: 'mrkdwn', text: '*Fatal:*\n' + err.is_fatal },
            { type: 'mrkdwn', text: '*Description:*\n' + err.description },
            { type: 'mrkdwn', text: '*Trace ID:*\n`' + err.trace_id + '`' },
            { type: 'mrkdwn', text: '*From:*\n' + (data.channel ? data.channel.from : 'unknown') },
            { type: 'mrkdwn', text: '*To:*\n' + (data.channel ? data.channel.to : 'unknown') },
            { type: 'mrkdwn', text: '*Time:*\n' + err.timestamp }
          ]
        }
      ]
    },
    json: true
  });
} catch (e) {
  // Swallow — alert failure must not mask the original error
}

return [$input.first()];
